import time

from django.conf import settings
from django.http import HttpResponse
from django.utils.deprecation import MiddlewareMixin


class RateLimitMiddleware(MiddlewareMixin):
    """
    Rate-limit incoming HTTP requests by client IP address.

    When a client exceeds RATE_LIMIT_REQUESTS requests within RATE_LIMIT_WINDOW
    seconds, further requests are rejected with a 403 Forbidden response.
    """

    def __init__(self, get_response):
        super().__init__(get_response)
        self.rate_limit_requests = getattr(settings, "RATE_LIMIT_REQUESTS", 100)
        self.rate_limit_window = getattr(settings, "RATE_LIMIT_WINDOW", 3600)
        # Maps IP address -> list of request timestamps within the current window
        self._request_log = {}
        self._request_count = 0

    def _get_client_ip(self, request):
        x_forwarded_for = request.META.get("HTTP_X_FORWARDED_FOR")
        if x_forwarded_for:
            return x_forwarded_for.split(",")[0].strip()
        return request.META.get("REMOTE_ADDR", "")

    def _cleanup_expired(self, now):
        cutoff = now - self.rate_limit_window
        expired_ips = [
            ip
            for ip, timestamps in self._request_log.items()
            if not timestamps or timestamps[-1] < cutoff
        ]
        for ip in expired_ips:
            del self._request_log[ip]

    def process_request(self, request):
        now = time.time()
        self._request_count += 1
        if self._request_count % 100 == 0:
            self._cleanup_expired(now)

        ip = self._get_client_ip(request)
        cutoff = now - self.rate_limit_window
        timestamps = self._request_log.get(ip, [])
        # Discard timestamps outside the current window
        timestamps = [t for t in timestamps if t >= cutoff]
        timestamps.append(now)
        self._request_log[ip] = timestamps

        if len(timestamps) > self.rate_limit_requests:
            return HttpResponse(
                "Rate limit exceeded for IP %s" % ip,
                status=403,
            )

